VALUES
  ('dietitian-moex-00513', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關接受腹膜透析（peritoneal dialysis）病人之營養照護原則，下列何者最不適當？', '["依不同年齡層，熱量攝取範圍為30～35大卡／公斤／天，進行飲食設計時需扣除每日由透析液葡萄糖所供 應之熱量", "飲食磷離子之建議攝取範圍為0.8～1.2克／天", "蛋白質需求量為1.2～1.5克／公斤／天，而高生理價蛋白質（如：奶類及肉類）通常磷離子含量較高，其 食用份數必須適量不超過建議範圍", "使用calcium carbonate作為磷結合劑的一種藥物時，建議餐後服用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00514', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '對於腎結石病人，最適當的每日鈣建議攝取量（mg）為多少？', '["300", "600", "1,000", "2,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00515', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關心臟移植手術後的營養支持，下列敘述何者最不適當？', '["移植後的前期（immediate posttransplant）代謝分解增加（catabolism），故需要給予較多的蛋白質", "病人常因移植前惡病質（cachectic）消瘦，所以移植後的前期（immediate posttransplant）血糖會比較 穩定", "體重增加過多是移植後（long-term posttransplant）常見的合併症（comorbid）", "移植後長期使用類固醇治療，因此需要攝取適當的鈣質與維生素D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00516', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關預防心血管疾病的營養處置，下列敘述何者最不適當？', '["依據2013年美國心臟醫學會／美國心臟協會（American College of Cardiology / American Heart Accociation, ACC/AHA）發表的臨床指引，飲食中的膽固醇並不會增加血液中的低密度脂蛋白膽固醇，因此 預防心血管疾病的飲食不需再限制膽固醇的攝取", "有關得舒飲食的變化（DASH variations），若以單元不飽和脂肪取代10%的醣類熱量，會有較佳的降血壓 效果", "2013年美國心臟醫學會／美國心臟協會（American College of Cardiology / American Heart Accociation, ACC/AHA）發表的臨床指引，建議若須降低低密度脂蛋白膽固醇，每日飽和脂肪的攝取為10% 總熱量", "非水溶性纖維（如cellulose、lignin）無降血膽固醇效果，若要預防心血管疾病建議可多攝取水溶性纖維"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00517', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關高血壓營養治療中的礦物質需求，下列敘述何者最不適當？', '["鈣的攝取量建議符合Recommended Dietary Allowance（RDA）", "建議優先使用鎂離子補充劑", "建議鹽攝取＜6 g/day（＜2.3 g 鈉/day）", "建議攝取鉀離子約4.7 g/day"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00518', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列關於DASH飲食的內容何者錯誤？', '["選用瘦肉及脫脂奶", "多攝食天然蔬果", "增加堅果攝食", "使用「低鈉鹽」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00519', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關重症病人的血糖控制範圍，下列何者對於病人的預後最佳？', '["100～126 mg/dL", "140～180 mg/dL", "200～250 mg/dL", "＜100 mg/dL"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00520', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', 'Quick Sequential Organ Failure Assessment（qSOFA）可以用來評估可能發展為敗血症的病人，其三項判 定指標中不包含下列何項？', '["體溫＞38℃", "改變意識狀態（Glasgow Coma Scale＜15）", "收縮壓（systolic blood pressure）≦100 mmHg", "呼吸速率≧22次／分鐘"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
