  ('dietitian-moex-00522', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '腸缺血（bowel ischemia）的病人開始灌食，最不適用下列何種配方或飲食？', '["預解配方", "含纖配方", "清流配方", "低渣配方"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
